use super::*;
use crate::lrat_parser::LratStep;

/// PHP(3,2): pigeonhole principle, 3 pigeons into 2 holes.
/// 6 variables, 9 clauses. Proof generated by z4.
#[test]
fn test_end_to_end_php32() {
    let cnf = b"\
p cnf 6 9
1 2 0
3 4 0
5 6 0
-1 -3 0
-1 -5 0
-3 -5 0
-2 -4 0
-2 -6 0
-4 -6 0
";
    // Step 24 derives the empty clause from hints [22, 10, 20].
    // Previously had a trailing "26 0 0" (empty clause, no hints) which was
    // accepted due to a soundness bug --- now removed.
    let proof = "\
10 2 -3 0 4 1 0
11 2 -5 0 5 1 0
12 d 1 4 5 0
13 3 -2 0 7 2 0
14 3 -6 0 9 2 0
15 d 2 7 9 0
16 6 -3 0 6 3 0
17 6 2 0 11 3 0
18 d 3 6 11 0
19 -3 -2 0 8 16 0
20 2 3 0 14 17 0
21 d 16 17 8 14 0
22 -2 0 13 19 0
23 d 13 0
24 0 22 10 20 0
25 d 19 20 10 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(checker.verify_proof(&steps));
    assert_eq!(checker.stats.failures, 0);
    assert!(checker.stats.derived > 0);
    assert!(checker.stats.deleted > 0);
}

