/// Trivially UNSAT: (a v b) ^ (~a v b) ^ (a v ~b) ^ (~a v ~b).
/// Proof generated by z4.
#[test]
fn test_end_to_end_trivial_unsat() {
    let cnf = b"\
p cnf 2 4
1 2 0
-1 2 0
1 -2 0
-1 -2 0
";
    // Step 5 derives (b) from clauses 2,1; step 6 derives (~b) from 4,3;
    // step 7 derives empty clause from 5,6 (b and ~b conflict).
    let proof = "\
5 2 0 2 1 0
6 -2 0 4 3 0
7 0 5 6 0
8 d 1 3 2 4 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(checker.verify_proof(&steps));
}

/// Corrupted proof: tamper with a hint to make it invalid.
#[test]
fn test_reject_corrupted_proof_bad_hint() {
    let cnf = b"\
p cnf 2 4
1 2 0
-1 2 0
1 -2 0
-1 -2 0
";
    // Valid proof but with hint 999 (nonexistent) instead of hint 2.
    let proof = "\
5 2 0 999 1 0
6 -2 0 4 3 0
7 0 5 6 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(!checker.verify_proof(&steps));
}

