/// Soundness test: empty clause with no hints must be rejected.
///
/// This was a critical soundness bug: verify_chain returned true for
/// empty clause + empty hints, allowing any formula to be "proven" UNSAT.
/// The LRAT spec requires that the empty clause derivation be justified by
/// hints that produce a conflict under unit propagation.
#[test]
fn test_reject_empty_clause_with_no_hints() {
    // Satisfiable formula: (a v b)
    let mut checker = LratChecker::new(2);
    checker.add_original(1, &[lit(1), lit(2)]);

    let steps = vec![LratStep::Add {
        id: 2,
        clause: vec![],
        hints: vec![],
    }];

    assert!(
        !checker.verify_proof(&steps),
        "Empty clause with no hints must be rejected on a SAT formula"
    );
}

/// Binary LRAT format end-to-end: PHP(2,1) encoded in binary.
#[test]
fn test_end_to_end_binary_lrat() {
    let cnf = b"\
p cnf 2 3
1 0
2 0
-1 -2 0
";
    // Binary LRAT for PHP(2,1): derive empty clause from {1}, {-1,-2}, {2}.
    // Step: add id=4 clause=[] hints=[1,3,2]
    // Binary encodes IDs as 2*value: id=4->8, hint=1->2, hint=3->6, hint=2->4
    let proof_data: Vec<u8> = vec![b'a', 8, 0, 2, 6, 4, 0];
    let steps = crate::lrat_parser::parse_binary_lrat(&proof_data).unwrap();

    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(checker.verify_proof(&steps));
}

/// Binary LRAT end-to-end with deletions: encode a proof containing both
/// addition and deletion steps in binary format, parse and verify.
/// This tests the full pipeline for binary 'd' markers through the checker.
///
/// Formula (XOR-2, UNSAT):
///   C1=(a v b) id=1, C2=(~a v b) id=2, C3=(a v ~b) id=3, C4=(~a v ~b) id=4
///
/// Proof:
///   step 1: add id=5 clause=(b) hints=[1,2]     -- RUP: ~b -> C1 forces a -> C2 conflict
///   step 2: delete [1, 2]                         -- remove C1, C2
///   step 3: add id=6 clause=(~b) hints=[3,4]    -- RUP: b -> C3 forces a -> C4 conflict
///   step 4: add id=7 clause=() hints=[5,6]       -- empty clause from (b) and (~b)
#[test]
fn test_end_to_end_binary_lrat_with_deletions() {
    let cnf = b"\
p cnf 2 4
1 2 0
-1 2 0
1 -2 0
-1 -2 0
";
    // Binary encoding:
    // IDs: encoded = 2*value. Lits: pos v -> 2*v, neg v -> 2*v+1.
    let proof_data: Vec<u8> = vec![
        // add id=5(10), clause=[2(4)], 0, hints=[1(2), 2(4)], 0
        b'a', 10, 4, 0, 2, 4, 0, // delete [1(2), 2(4)], 0
        b'd', 2, 4, 0, // add id=6(12), clause=[-2(5)], 0, hints=[3(6), 4(8)], 0
        b'a', 12, 5, 0, 6, 8, 0, // add id=7(14), clause=[], 0, hints=[5(10), 6(12)], 0
        b'a', 14, 0, 10, 12, 0,
    ];

    let steps = crate::lrat_parser::parse_binary_lrat(&proof_data).unwrap();
    assert_eq!(steps.len(), 4, "expected 4 steps (3 adds + 1 delete)");

    // Verify deletion was parsed correctly.
    match &steps[1] {
        crate::lrat_parser::LratStep::Delete { ids } => {
            assert_eq!(ids, &[1, 2], "deletion must remove clause IDs 1 and 2");
        }
        other => panic!("step 2 must be Delete, got: {other:?}"),
    }

    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(
        checker.verify_proof(&steps),
        "binary LRAT proof with deletions must verify"
    );
}

// --- drat-trim cross-validation tests (#5243) ---
//
// Verify z4-lrat-check produces the same results as drat-trim's lrat-check.c
// on all example CNF+LRAT pairs from the drat-trim repository.
// These examples contain RAT steps (negative hint IDs for witness clauses).

/// Helper: load a CNF+LRAT file pair and verify.
fn verify_drat_trim_example(name: &str) {
    let base = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../../reference/drat-trim/examples/"
    );
    let cnf_path = format!("{base}{name}.cnf");
    let lrat_path = format!("{base}{name}.lrat");

    let cnf_data =
        std::fs::read(&cnf_path).unwrap_or_else(|e| panic!("failed to read {cnf_path}: {e}"));
    let lrat_data = std::fs::read_to_string(&lrat_path)
        .unwrap_or_else(|e| panic!("failed to read {lrat_path}: {e}"));

    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf_data[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(&lrat_data).unwrap();

    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(
        checker.verify_proof(&steps),
        "drat-trim example {name} must verify (parity with drat-trim lrat-check.c)"
    );
}

