// ─── RAT soundness tests (adversarial) ──────────────────────────────

/// RAT with incomplete witnesses: omits C5(¬a∨c). Completeness check rejects.
#[test]
fn test_e2e_rat_incomplete_witnesses_rejected() {
    let cnf = b"\
p cnf 3 5
1 2 0
-1 2 0
1 -2 0
-1 -2 0
-1 3 0
";
    // RAT derive (a) with witnesses for C2(id=2) and C4(id=4), but NOT C5(id=5).
    // C5 contains ~a and has no witness → must fail completeness check.
    let proof = "\
6 1 0 -2 1 -4 3 0
7 -1 0 4 2 0
8 0 6 7 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(
        !checker.verify_proof(&steps),
        "RAT proof with incomplete witnesses must be rejected"
    );
}

/// Delete ~pivot clause before RAT step. Deleted clause needs no witness.
#[test]
fn test_e2e_rat_after_deletion_succeeds() {
    let cnf = b"\
p cnf 3 5
1 2 0
-1 2 0
1 -2 0
-1 -2 0
-1 3 0
";
    // Delete C5 first, then RAT-derive (a) with witnesses for C2 and C4.
    let proof = "\
6 d 5 0
7 1 0 -2 1 -4 3 0
8 -1 0 4 2 0
9 0 7 8 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(
        checker.verify_proof(&steps),
        "RAT after deleting ~pivot clause must succeed (deleted clauses need no witness)"
    );
}

/// RAT must cover derived clauses too. Derive (¬a) by RUP, then RAT-derive (a)
/// without witness for the derived (¬a) clause — must fail.
#[test]
fn test_e2e_rat_must_cover_derived_clauses() {
    let cnf = b"\
p cnf 2 4
1 2 0
-1 2 0
1 -2 0
-1 -2 0
";
    // Derive (~a) by RUP, then RAT (a) with witnesses for C2, C4 only — misses derived C5.
    let proof = "\
5 -1 0 4 2 0
6 1 0 -2 1 -4 3 0
7 0 5 6 0
";
    let crate::dimacs::CnfFormulaWithIds { num_vars, clauses } =
        crate::dimacs::parse_cnf_with_ids(&cnf[..]).unwrap();
    let steps = crate::lrat_parser::parse_text_lrat(proof).unwrap();
    let mut checker = LratChecker::new(num_vars);
    for (id, clause) in &clauses {
        checker.add_original(*id, clause);
    }
    assert!(
        !checker.verify_proof(&steps),
        "RAT must cover derived clauses containing ~pivot, not just originals"
    );
}
